/*
 * COMP 321 Project 6: Web Proxy
 *
 * This program implements a multithreaded HTTP proxy.
 *
 * <Replace with your name(s) and NetID(s).>
 */

#include <assert.h>

#include "csapp.h"

/* Number of prethreaded worker threads and bounded buffer capacity. */
#define NTHREADS  10
#define SBUFSIZE  16

/* ============================================================
 * Bounded buffer for prethreading (using mutex + cond vars).
 * ============================================================ */

typedef struct {
	int            *buf;        /* Array of connection fds */
	int             n;          /* Maximum slots */
	int             front;      /* front slot index */
	int             rear;       /* one past last slot index */
	pthread_mutex_t mutex;
	pthread_cond_t  not_empty;  /* signalled when item inserted */
	pthread_cond_t  not_full;   /* signalled when item removed */
} sbuf_t;

static sbuf_t sbuf;

static void
sbuf_init(sbuf_t *sp, int n)
{
	sp->buf   = Malloc(n * sizeof(int));
	sp->n     = n;
	sp->front = sp->rear = 0;
	pthread_mutex_init(&sp->mutex, NULL);
	pthread_cond_init(&sp->not_empty, NULL);
	pthread_cond_init(&sp->not_full, NULL);
}

/* Insert item onto the rear of shared buffer sp. */
static void
sbuf_insert(sbuf_t *sp, int item)
{
	pthread_mutex_lock(&sp->mutex);
	while (sp->rear - sp->front == sp->n)
		pthread_cond_wait(&sp->not_full, &sp->mutex);
	sp->buf[(sp->rear++) % sp->n] = item;
	pthread_cond_signal(&sp->not_empty);
	pthread_mutex_unlock(&sp->mutex);
}

/* Remove and return the front item from shared buffer sp. */
static int
sbuf_remove(sbuf_t *sp)
{
	int item;

	pthread_mutex_lock(&sp->mutex);
	while (sp->rear == sp->front)
		pthread_cond_wait(&sp->not_empty, &sp->mutex);
	item = sp->buf[(sp->front++) % sp->n];
	pthread_cond_signal(&sp->not_full);
	pthread_mutex_unlock(&sp->mutex);
	return item;
}

/* ============================================================
 * Log file (opened once at startup).
 * ============================================================ */

static FILE           *log_file;
static pthread_mutex_t log_mutex = PTHREAD_MUTEX_INITIALIZER;

/* ============================================================
 * Forward declarations of provided helper functions.
 * ============================================================ */

static void  client_error(int fd, const char *cause, int err_num,
		    const char *short_msg, const char *long_msg);
static char *create_log_entry(const struct sockaddr_in *sockaddr,
		    const char *uri, int size);
static int   parse_uri(const char *uri, char **hostnamep, char **portp,
		    char **pathnamep);

/* Forward declarations of new functions. */
static int   connect_to_server(const char *hostname, const char *port);
static void  handle_request(int connfd);
static void *worker_thread(void *vargp);

/* ============================================================
 * connect_to_server: open a TCP connection to hostname:port.
 * Returns the fd on success or -1 on any failure (including DNS
 * failure).  Does NOT call exit() on error, unlike open_clientfd.
 * ============================================================ */

/*
 * Requires:
 *   hostname and port are NUL-terminated strings.
 *
 * Effects:
 *   Resolves hostname and attempts to connect on port.  Returns
 *   the connected socket fd on success, or -1 on any failure.
 */
static int
connect_to_server(const char *hostname, const char *port)
{
	struct addrinfo  hints, *listp, *p;
	int              clientfd = -1, rc;

	memset(&hints, 0, sizeof(struct addrinfo));
	hints.ai_socktype = SOCK_STREAM;
	hints.ai_flags    = AI_NUMERICSERV;

	if ((rc = getaddrinfo(hostname, port, &hints, &listp)) != 0)
		return -1;  /* DNS failure: return -1, don't exit */

	for (p = listp; p != NULL; p = p->ai_next) {
		clientfd = socket(p->ai_family, p->ai_socktype, p->ai_protocol);
		if (clientfd < 0)
			continue;
		if (connect(clientfd, p->ai_addr, p->ai_addrlen) != -1)
			break;  /* Connected successfully */
		close(clientfd);
		clientfd = -1;
	}

	freeaddrinfo(listp);
	return clientfd;  /* -1 if all attempts failed */
}

/* ============================================================
 * Worker thread: repeatedly removes a connfd from the shared
 * buffer and handles the request.
 * ============================================================ */

/*
 * Requires:
 *   vargp is unused.
 *
 * Effects:
 *   Detaches itself, then loops forever: removes one connection
 *   fd from the shared buffer, handles the HTTP transaction,
 *   and closes the connection.
 */
static void *
worker_thread(void *vargp)
{
	int connfd;

	pthread_detach(pthread_self());
	(void)vargp;
	while (1) {
		connfd = sbuf_remove(&sbuf);
		handle_request(connfd);
		close(connfd);
	}
	/* NOTREACHED */
	return NULL;
}

/* ============================================================
 * handle_request: service one HTTP GET transaction.
 * ============================================================ */

/*
 * Requires:
 *   connfd is a valid, open socket connected to a client.
 *
 * Effects:
 *   Reads an HTTP GET request from the client, connects to the
 *   end server, forwards the (modified) request, reads the
 *   response, and returns it to the client.  Logs completed
 *   transactions to proxy.log.  Sends an HTTP error response to
 *   the client when the request is malformed or the server
 *   cannot be reached (provided forwarding has not yet started).
 */
static void
handle_request(int connfd)
{
	char            buf[MAXLINE];
	char            method[MAXLINE], uri[MAXLINE], version[MAXLINE];
	char            response_buf[MAXBUF];
	char           *hostname = NULL, *port = NULL, *pathname = NULL;
	rio_t           rio_client, rio_server;
	int             serverfd = -1;
	int             total_size = 0;
	int             header_err = 0;
	ssize_t         n;
	struct sockaddr_in clientaddr;
	socklen_t       clientlen = sizeof(clientaddr);

	/* Obtain client IP for logging. */
	if (getpeername(connfd, (SA *)&clientaddr, &clientlen) < 0)
		memset(&clientaddr, 0, sizeof(clientaddr));

	rio_readinitb(&rio_client, connfd);

	/* Read the HTTP request line. */
	if (rio_readlineb(&rio_client, buf, MAXLINE) <= 0)
		return;

	/* Parse method, URI, and HTTP version. */
	if (sscanf(buf, "%s %s %s", method, uri, version) != 3) {
		client_error(connfd, buf, 400, "Bad Request",
		    "Could not parse the request");
		return;
	}

	/* Only GET is supported. */
	if (strcasecmp(method, "GET") != 0) {
		client_error(connfd, method, 501, "Not Implemented",
		    "Proxy does not implement this method");
		/* Drain remaining headers so the client connection is clean. */
		while (rio_readlineb(&rio_client, buf, MAXLINE) > 0)
			if (strcmp(buf, "\r\n") == 0) break;
		return;
	}

	/* Parse the URI into hostname, port, and pathname. */
	if (parse_uri(uri, &hostname, &port, &pathname) < 0) {
		client_error(connfd, uri, 400, "Bad Request",
		    "Could not parse the URI");
		while (rio_readlineb(&rio_client, buf, MAXLINE) > 0)
			if (strcmp(buf, "\r\n") == 0) break;
		return;
	}

	/* Open a connection to the end server. */
	serverfd = connect_to_server(hostname, port);
	if (serverfd < 0) {
		client_error(connfd, hostname, 404, "Not Found",
		    "Could not connect to end server");
		while (rio_readlineb(&rio_client, buf, MAXLINE) > 0)
			if (strcmp(buf, "\r\n") == 0) break;
		free(hostname);
		free(port);
		free(pathname);
		return;
	}

	/*
	 * Forward a rewritten request line to the end server.
	 * Use only the path (not the full URI) and downgrade to HTTP/1.0
	 * to avoid persistent-connection complications.
	 */
	snprintf(buf, MAXLINE, "GET %s HTTP/1.0\r\n", pathname);
	if (rio_writen(serverfd, buf, strlen(buf)) < 0)
		goto cleanup;

	/* Always send a Host header (using the parsed hostname). */
	snprintf(buf, MAXLINE, "Host: %s\r\n", hostname);
	if (rio_writen(serverfd, buf, strlen(buf)) < 0)
		goto cleanup;

	/*
	 * Forward the client's remaining headers to the end server,
	 * stripping Connection, Keep-Alive, Proxy-Connection, and Host
	 * (we already sent Host above).
	 */
	while (!header_err) {
		n = rio_readlineb(&rio_client, buf, MAXLINE);
		if (n <= 0)
			break;
		if (strcmp(buf, "\r\n") == 0)
			break;

		if (strncasecmp(buf, "Connection:",      11) == 0 ||
		    strncasecmp(buf, "Keep-Alive:",      11) == 0 ||
		    strncasecmp(buf, "Proxy-Connection:", 17) == 0 ||
		    strncasecmp(buf, "Host:",             5) == 0)
			continue;

		if (rio_writen(serverfd, buf, strlen(buf)) < 0)
			header_err = 1;
	}

	if (header_err)
		goto cleanup;

	/* Terminate headers and request that the server close after reply. */
	if (rio_writen(serverfd, "Connection: close\r\n\r\n", 21) < 0)
		goto cleanup;

	/*
	 * Read the end server's response and pipe it back to the client.
	 * Count bytes for the log entry.
	 */
	rio_readinitb(&rio_server, serverfd);
	while ((n = rio_readnb(&rio_server, response_buf, MAXBUF)) > 0) {
		if (rio_writen(connfd, response_buf, n) < 0)
			break;
		total_size += (int)n;
	}

	/* Log the completed transaction (server responded). */
	{
		char *log_entry = create_log_entry(&clientaddr, uri,
		    total_size);
		pthread_mutex_lock(&log_mutex);
		fprintf(log_file, "%s\n", log_entry);
		fflush(log_file);
		pthread_mutex_unlock(&log_mutex);
		free(log_entry);
	}

cleanup:
	if (serverfd >= 0)
		close(serverfd);
	free(hostname);
	free(port);
	free(pathname);
}

/* ============================================================
 * main
 * ============================================================ */

/*
 * Requires:
 *   A single command-line argument: the port number on which the
 *   proxy should listen.
 *
 * Effects:
 *   Ignores SIGPIPE, opens proxy.log, creates a pool of worker
 *   threads, then accepts incoming connections in a loop and
 *   inserts each accepted fd into the shared buffer for a worker
 *   thread to handle.
 */
int
main(int argc, char **argv)
{
	int                listenfd, connfd;
	socklen_t          clientlen;
	struct sockaddr_in clientaddr;
	pthread_t          tid;
	int                i;

	/* Check the arguments. */
	if (argc != 2) {
		fprintf(stderr, "Usage: %s <port number>\n", argv[0]);
		exit(0);
	}

	/*
	 * Ignore SIGPIPE so that writing to a connection closed by the
	 * peer does not kill the process.
	 */
	Signal(SIGPIPE, SIG_IGN);

	/* Open the log file exactly once at startup. */
	log_file = fopen("proxy.log", "w");
	if (log_file == NULL) {
		fprintf(stderr, "Error: cannot open proxy.log\n");
		exit(1);
	}

	/* Initialise the shared bounded buffer and spawn worker threads. */
	sbuf_init(&sbuf, SBUFSIZE);
	for (i = 0; i < NTHREADS; i++)
		pthread_create(&tid, NULL, worker_thread, NULL);

	/* Accept connection requests and hand them to worker threads. */
	listenfd = open_listenfd(argv[1]);
	if (listenfd < 0) {
		fprintf(stderr, "Error: cannot open listen socket on port %s\n",
		    argv[1]);
		exit(1);
	}
	while (1) {
		clientlen = sizeof(struct sockaddr_in);
		connfd = accept(listenfd, (SA *)&clientaddr, &clientlen);
		if (connfd < 0)
			continue;
		sbuf_insert(&sbuf, connfd);
	}

	/* Return success. */
	return (0);
}

/* ============================================================
 * parse_uri  (provided)
 * ============================================================ */

/*
 * Requires:
 *   The parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Given a URI from an HTTP proxy GET request (i.e., a URL), extract the
 *   host name, port, and path name.  Create strings containing the host name,
 *   port, and path name, and return them through the parameters "hostnamep",
 *   "portp", "pathnamep", respectively.  (The caller must free the memory
 *   storing these strings.)  Return -1 if there are any problems and 0
 *   otherwise.
 */
static int
parse_uri(const char *uri, char **hostnamep, char **portp, char **pathnamep)
{
	const char *pathname_begin, *port_begin, *port_end;

	if (strncasecmp(uri, "http://", 7) != 0)
		return (-1);

	/* Extract the host name. */
	const char *host_begin = uri + 7;
	const char *host_end = strpbrk(host_begin, ":/ \r\n");
	if (host_end == NULL)
		host_end = host_begin + strlen(host_begin);
	int len = host_end - host_begin;
	char *hostname = Malloc(len + 1);
	strncpy(hostname, host_begin, len);
	hostname[len] = '\0';
	*hostnamep = hostname;

	/* Look for a port number.  If none is found, use port 80. */
	if (*host_end == ':') {
		port_begin = host_end + 1;
		port_end = strpbrk(port_begin, "/ \r\n");
		if (port_end == NULL)
			port_end = port_begin + strlen(port_begin);
		len = port_end - port_begin;
	} else {
		port_begin = "80";
		port_end = host_end;
		len = 2;
	}
	char *port = Malloc(len + 1);
	strncpy(port, port_begin, len);
	port[len] = '\0';
	*portp = port;

	/* Extract the path. */
	if (*port_end == '/') {
		pathname_begin = port_end;
		const char *pathname_end = strpbrk(pathname_begin, " \r\n");
		if (pathname_end == NULL)
			pathname_end = pathname_begin + strlen(pathname_begin);
		len = pathname_end - pathname_begin;
	} else {
		pathname_begin = "/";
		len = 1;
	}
	char *pathname = Malloc(len + 1);
	strncpy(pathname, pathname_begin, len);
	pathname[len] = '\0';
	*pathnamep = pathname;

	return (0);
}

/* ============================================================
 * create_log_entry  (provided)
 * ============================================================ */

/*
 * Requires:
 *   The parameter "sockaddr" must point to a valid sockaddr_in structure.  The
 *   parameter "uri" must point to a properly NUL-terminated string.
 *
 * Effects:
 *   Returns a string containing a properly formatted log entry.  This log
 *   entry is based upon the socket address of the requesting client
 *   ("sockaddr"), the URI from the request ("uri"), and the size in bytes of
 *   the response from the server ("size").
 */
static char *
create_log_entry(const struct sockaddr_in *sockaddr, const char *uri, int size)
{
	struct tm result;

	/*
	 * Create a large enough array of characters to store a log entry.
	 * Although the length of the URI can exceed MAXLINE, the combined
	 * lengths of the other fields and separators cannot.
	 */
	const size_t log_maxlen = MAXLINE + strlen(uri);
	char *const log_str = Malloc(log_maxlen + 1);

	/* Get a formatted time string. */
	time_t now = time(NULL);
	int log_strlen = strftime(log_str, MAXLINE, "%a %d %b %Y %H:%M:%S %Z: ",
	    localtime_r(&now, &result));

	/*
	 * Convert the IP address in network byte order to dotted decimal
	 * form.
	 */
	Inet_ntop(AF_INET, &sockaddr->sin_addr, &log_str[log_strlen],
	    INET_ADDRSTRLEN);
	log_strlen += strlen(&log_str[log_strlen]);

	/*
	 * Assert that the time and IP address fields occupy less than half of
	 * the space that is reserved for the non-URI fields.
	 */
	assert(log_strlen < MAXLINE / 2);

	/*
	 * Add the URI and response size onto the end of the log entry.
	 */
	snprintf(&log_str[log_strlen], log_maxlen - log_strlen, " %s %d", uri,
	    size);

	return (log_str);
}

/* ============================================================
 * client_error  (provided)
 * ============================================================ */

/*
 * Requires:
 *   The parameter "fd" must be an open socket that is connected to the client.
 *   The parameters "cause", "short_msg", and "long_msg" must point to properly
 *   NUL-terminated strings that describe the reason why the HTTP transaction
 *   failed.  The string "short_msg" may not exceed 32 characters in length,
 *   and the string "long_msg" may not exceed 80 characters in length.
 *
 * Effects:
 *   Constructs an HTML page describing the reason why the HTTP transaction
 *   failed, and writes an HTTP/1.0 response containing that page as the
 *   content.  The cause appearing in the HTML page is truncated if the
 *   string "cause" exceeds 2048 characters in length.
 */
static void
client_error(int fd, const char *cause, int err_num, const char *short_msg,
    const char *long_msg)
{
	char body[MAXBUF], headers[MAXBUF], truncated_cause[2049];

	assert(strlen(short_msg) <= 32);
	assert(strlen(long_msg) <= 80);
	/* Ensure that "body" is much larger than "truncated_cause". */
	assert(sizeof(truncated_cause) < MAXBUF / 2);

	/*
	 * Create a truncated "cause" string so that the response body will not
	 * exceed MAXBUF.
	 */
	strncpy(truncated_cause, cause, sizeof(truncated_cause) - 1);
	truncated_cause[sizeof(truncated_cause) - 1] = '\0';

	/* Build the HTTP response body. */
	snprintf(body, MAXBUF,
	    "<html><title>Proxy Error</title><body bgcolor=""ffffff"">\r\n"
	    "%d: %s\r\n"
	    "<p>%s: %s\r\n"
	    "<hr><em>The COMP 321 Web proxy</em>\r\n",
	    err_num, short_msg, long_msg, truncated_cause);

	/* Build the HTTP response headers. */
	snprintf(headers, MAXBUF,
	    "HTTP/1.0 %d %s\r\n"
	    "Content-type: text/html\r\n"
	    "Content-length: %d\r\n"
	    "\r\n",
	    err_num, short_msg, (int)strlen(body));

	/* Write the HTTP response. */
	if (rio_writen(fd, headers, strlen(headers)) != -1)
		rio_writen(fd, body, strlen(body));
}
